2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (isLive: boolean, neighborCount: number): boolean =>
12	  neighborCount === 3 || (isLive && neighborCount === 2);
13	
14	const neighborsOf = ([x, y]: Cell): Cell[] =>
15	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
16	
17	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
18	  const liveKeys = new Set(liveCells.map(keyOf));
19	  const neighborCounts = new Map<string, number>();
20	  const candidates = new Map<string, Cell>();
21	
22	  for (const liveCell of liveCells) {
23	    for (const neighbor of neighborsOf(liveCell)) {
24	      const key = keyOf(neighbor);
25	      candidates.set(key, neighbor);
26	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
27	    }
28	  }
29	
30	  const next: Cell[] = [];
31	  for (const [key, cell] of candidates) {
32	    if (survives(liveKeys.has(key), neighborCounts.get(key) ?? 0)) next.push(cell);
33	  }
34	  return next;
35	};
